INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 10139, "2024/02/14 12:00:00", 0.0, 57, -416.5, 1, 5, "2024/02/26 14:59:59", 10139005, 0.0);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 10139, "2024/02/14 12:00:00", 0.0, 55, -363.0, 2, 1, "2024/02/26 14:59:59", 10139006, 5.506);
