INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 20047, "2023/11/16 15:00:00", 0.0, 53, -416.5, 2, 1, "2030/01/01 14:59:59", 20047001, 3.414);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "ミッションをクリアして、\n報酬をゲットしましょう！", 20047, "2023/11/16 15:00:00", 0.0, 53, -416.5, 2, 2, "2030/01/01 14:59:59", 20047002, 3.099);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "受け取ることができる\n報酬があるようです\n確認してみてください", 20047, "2023/11/16 15:00:00", 0.0, 54, -416.5, 2, 3, "2030/01/01 14:59:59", 20047003, 2.801);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 2, "報酬がもらえますよ！\nチェックしてみてください", 20047, "2023/11/16 15:00:00", 0.0, 54, -416.5, 2, 4, "2030/01/01 14:59:59", 20047004, 0.0);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 20047, "2023/11/16 15:00:00", 0.0, 57, -416.5, 1, 5, "2030/01/01 14:59:59", 20047005, 0.0);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 1, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 20047, "2023/11/16 15:00:00", 0.0, 55, -363.0, 2, 1, "2030/01/01 14:59:59", 20047006, 5.506);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 2, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 20047, "2023/11/16 15:00:00", 0.0, 55, -363.0, 1, 2, "2030/01/01 14:59:59", 20047007, 1.216);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 2, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 20047, "2023/11/16 15:00:00", 0.0, 56, -363.0, 1, 3, "2030/01/01 14:59:59", 20047008, 1.539);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES ("カリン", 190801, 2, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 20047, "2023/11/16 15:00:00", 0.0, 56, -363.0, 1, 4, "2030/01/01 14:59:59", 20047009, 1.875);
